function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

interface Question {
  id: number;
  text: string;
  options: string[];
  correctAnswer: string;
  category: "world_cup" | "champions_league" | "la_liga" | "mixed" | "serie_a" | "bundesliga" | "iraqi_league" | "who_am_i" | "arab_cup" | "ligue_1";
}

interface Player {
  id: string;
  name: string;
  score: number;
  ws: WebSocket;
}

interface Room {
  id: string;
  players: Player[];
  gameState: 'waiting' | 'playing' | 'finished';
  questions: Question[];
  currentQuestionIndex: number;
  timeLeft: number;
  buzzedPlayerId: string | null;
  isAnswered: boolean;
  timerInterval?: NodeJS.Timeout;
  category: "world_cup" | "champions_league" | "la_liga" | "mixed" | "serie_a" | "bundesliga" | "iraqi_league" | "who_am_i" | "arab_cup" | "ligue_1";
}

const rooms = new Map<string, Room>();
const leaderboard: { name: string; score: number }[] = [];

function updateLeaderboard(players: Player[]) {
  players.forEach(p => {
    const existing = leaderboard.find(l => l.name === p.name);
    if (existing) {
      if (p.score > existing.score) {
        existing.score = p.score;
      }
    } else {
      leaderboard.push({ name: p.name, score: p.score });
    }
  });
  
  // Sort and keep top 10
  leaderboard.sort((a, b) => b.score - a.score);
  if (leaderboard.length > 10) leaderboard.length = 10;
}

function broadcast(room: Room, message: any) {
  const payload = JSON.stringify(message);
  room.players.forEach(p => {
    if (p.ws.readyState === WebSocket.OPEN) {
      p.ws.send(payload);
    }
  });
}

function startGame(room: Room) {
  room.gameState = 'playing';
  
  let availableQuestions = ALL_QUESTIONS;
  if (room.category !== "mixed") {
    availableQuestions = ALL_QUESTIONS.filter(q => q.category === room.category);
  }
  
  // If not enough questions in category, fallback to mixed
  if (availableQuestions.length < MAX_QUESTIONS_PER_MATCH) {
    availableQuestions = ALL_QUESTIONS;
  }

  room.questions = shuffleArray(availableQuestions).slice(0, MAX_QUESTIONS_PER_MATCH);
  room.currentQuestionIndex = 0;
  room.timeLeft = TIMER_START;
  room.buzzedPlayerId = null;
  room.isAnswered = false;
  
  startTimer(room);
  broadcast(room, { type: 'GAME_START', room: getRoomView(room) });
}

function handleNextQuestion(room: Room) {
  if (room.gameState !== 'playing' || !room.isAnswered) return;

  // Set isAnswered to false immediately to prevent double execution
  room.isAnswered = false;

  if (room.currentQuestionIndex < room.questions.length - 1) {
    room.currentQuestionIndex++;
    room.timeLeft = TIMER_START;
    room.buzzedPlayerId = null;
    broadcast(room, { type: "NEW_QUESTION", room: getRoomView(room) });
  } else {
    room.gameState = 'finished';
    updateLeaderboard(room.players);
    broadcast(room, { 
      type: "GAME_FINISHED", 
      players: room.players.map(p => ({ id: p.id, name: p.name, score: p.score })),
      leaderboard
    });
  }
}

function startTimer(room: Room) {
  if (room.timerInterval) clearInterval(room.timerInterval);
  
  room.timerInterval = setInterval(() => {
    if (room.gameState !== 'playing') {
      clearInterval(room.timerInterval);
      return;
    }

    if (room.timeLeft > 0 && !room.isAnswered) {
      room.timeLeft--;
      broadcast(room, { type: 'TIMER_TICK', timeLeft: room.timeLeft });
    } else if (room.timeLeft === 0 && !room.isAnswered) {
      room.isAnswered = true;
      broadcast(room, { type: 'TIME_UP' });
      setTimeout(() => handleNextQuestion(room), 3000);
    }
  }, 1000);
}

function getRoomView(room: Room) {
  return {
    id: room.id,
    gameState: room.gameState,
    currentQuestionIndex: room.currentQuestionIndex,
    totalQuestions: room.questions.length,
    timeLeft: room.timeLeft,
    buzzedPlayerId: room.buzzedPlayerId,
    isAnswered: room.isAnswered,
    players: room.players.map(p => ({ id: p.id, name: p.name, score: p.score })),
    question: room.questions[room.currentQuestionIndex]
  };
}

wss.on("connection", (ws) => {
  let currentPlayerId = nanoid();
  let currentRoomId: string | null = null;

  ws.on("message", (data) => {
    const message = JSON.parse(data.toString());

    switch (message.type) {
      case "JOIN_ROOM": {
        const { name, roomCode } = message;
        
        let room: Room | undefined;
        
        if (roomCode) {
          // Play with friend via specific code
          room = rooms.get(roomCode);
          
          if (!room) {
            // Create a new room with the provided code
            room = {
              id: roomCode,
              players: [],
              gameState: 'waiting',
              questions: [],
              currentQuestionIndex: 0,
              timeLeft: TIMER_START,
              buzzedPlayerId: null,
              isAnswered: false,
              category: "mixed"
            };
            rooms.set(roomCode, room);
          } else if (room.players.length >= 2 || room.gameState !== 'waiting') {
            // Room is full or already playing
            ws.send(JSON.stringify({ type: "ERROR", message: "ئەڤ ژوورە یا تژییە یان یاری تێدا دەستپێکریە" }));
            return;
          }
        } else {
          // Public Online Matchmaking
          // Find any public room waiting for a second player (public rooms have random 6-char IDs from nanoid)
          room = Array.from(rooms.values()).find(r => 
            r.gameState === 'waiting' && 
            r.players.length === 1 &&
            r.id.length === 6 // Assuming public rooms use the 6-char nanoid
          );

          if (!room) {
            // Create a new public room
            const roomId = nanoid(6);
            room = {
              id: roomId,
              players: [],
              gameState: 'waiting',
              questions: [],
              currentQuestionIndex: 0,
              timeLeft: TIMER_START,
              buzzedPlayerId: null,
              isAnswered: false,
              category: "mixed"
            };
            rooms.set(roomId, room);
          }
        }

        const player: Player = { id: currentPlayerId, name, score: 0, ws };
        room.players.push(player);
        currentRoomId = room.id;

        broadcast(room, { type: "PLAYER_JOINED", players: room.players.map(p => ({ id: p.id, name: p.name, score: p.score })) });
        ws.send(JSON.stringify({ 
          type: "JOIN_SUCCESS", 
          playerId: currentPlayerId, 
          room: getRoomView(room),
          leaderboard 
        }));

        if (room.players.length === 2) {
          startGame(room);
        }
        break;
      }

      case "ANSWER": {
        if (!currentRoomId) return;
        const room = rooms.get(currentRoomId);
        if (!room || room.gameState !== 'playing' || room.isAnswered) return;

        const { answer } = message;
        const question = room.questions[room.currentQuestionIndex];
        const isCorrect = answer === question.correctAnswer;

        room.isAnswered = true;
        room.buzzedPlayerId = currentPlayerId; // Track who answered first
        
        if (isCorrect) {
          const player = room.players.find(p => p.id === currentPlayerId);
          if (player) player.score += POINTS_PER_QUESTION;
        } else {
          // If incorrect, give points to the opponent
          const opponent = room.players.find(p => p.id !== currentPlayerId);
          if (opponent) opponent.score += POINTS_PER_QUESTION;
        }

        broadcast(room, { 
          type: "ANSWER_RESULT", 
          isCorrect, 
          correctAnswer: question.correctAnswer,
          selectedAnswer: answer,
          players: room.players.map(p => ({ id: p.id, name: p.name, score: p.score })),
          playerId: currentPlayerId // Inform client who answered
        });

        setTimeout(() => handleNextQuestion(room), 3000);
        break;
      }

      case "NEXT_QUESTION": {
        if (!currentRoomId) return;
        const room = rooms.get(currentRoomId);
        if (!room || !room.isAnswered) return;

        handleNextQuestion(room);
        break;
      }
    }
  });

  ws.on("close", () => {
    if (currentRoomId) {
      const room = rooms.get(currentRoomId);
      if (room) {
        room.players = room.players.filter(p => p.id !== currentPlayerId);
        if (room.players.length === 0) {
          if (room.timerInterval) clearInterval(room.timerInterval);
          rooms.delete(currentRoomId);
        } else {
          broadcast(room, { type: "PLAYER_LEFT", players: room.players.map(p => ({ id: p.id, name: p.name, score: p.score })) });
          if (room.gameState === 'playing') {
            room.gameState = 'finished';
            updateLeaderboard(room.players);
            broadcast(room, { 
              type: "GAME_FINISHED", 
              players: room.players.map(p => ({ id: p.id, name: p.name, score: p.score })), 
              reason: "Opponent left",
              leaderboard
            });
          }
        }
      }
    }
  });
});

async function start() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    app.use(express.static("dist"));
  }

  server.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

start();
